// Extrae session_id, index y metadata del callback_query de Telegram
const update = $json;
const callback = update.callback_query;

if (!callback || !callback.data) {
  throw new Error('No es un callback_query válido.');
}

const dataParts = callback.data.split(':');
if (dataParts.length !== 2) {
  throw new Error(`callback_data inválido: ${callback.data}`);
}

const [session_id, indexStr] = dataParts;
const index = parseInt(indexStr);

if (isNaN(index)) {
  throw new Error(`Índice inválido: ${indexStr}`);
}

const chat_id    = String(callback.message?.chat?.id || callback.from?.id || '8147167995');
const message_id = callback.message?.message_id;
const callback_query_id = callback.id;
const user_name = callback.from?.first_name || 'Usuario';

console.log(`Callback: session=${session_id}, index=${index}, user=${user_name}`);

return [{ json: {
  session_id,
  index,
  callback_query_id,
  chat_id,
  message_id,
  user_name
}}];

let aiText = $input.item.json.output || '';
aiText = aiText.replace(/```json/g, '').replace(/```/g, '').trim();
let storyboard;
try {
    storyboard = JSON.parse(aiText);
} catch(e) {
    storyboard = { scenes: [ { text: aiText.substring(0, 800), image_prompt: "abstract cinematic background", subtitle_pos: "center", subtitle_size: "large" } ] };
}
// Título desde el candidato elegido
storyboard.title = $('Obtener Candidato').first().json.title;
return storyboard;

