const storyboard = $('Parse JSON IA').item.json;
const batchResult = $input.item.json;
const candidato   = $('Obtener Candidato').first().json;

for (let i = 0; i < storyboard.scenes.length; i++) {
    storyboard.scenes[i].media_filename = "NICHE";
    storyboard.scenes[i].subtitle_pos   = storyboard.scenes[i].subtitle_pos  || "center";
    storyboard.scenes[i].subtitle_size  = storyboard.scenes[i].subtitle_size || 48;
}

return {
  title:     storyboard.title,
  scenes:    storyboard.scenes,
  niche:     candidato.niche,
  voice_id:  candidato.voice_id,
  tts_engine: "edge-tts",
  tts_speed:  1.1,
  batch_id:   batchResult.batch_id
};

